// Split incoming imagePayloads into one item per platform
const { postId, imagePayloads, callbackUrl } = $input.first().json;

if (!postId || !imagePayloads || !callbackUrl) {
  throw new Error('Missing required fields: postId, imagePayloads, callbackUrl');
}

const items = [];
for (const [platform, imgPayload] of Object.entries(imagePayloads)) {
  if (!imgPayload || !imgPayload.prompt) {
    console.log(`Skipping ${platform} - missing image prompt`);
    continue;
  }
  items.push({
    json: {
      postId,
      platform,
      prompt: imgPayload.prompt,
      sourceImageUrl: imgPayload.sourceImageUrl || null,
      styleDirectives: imgPayload.styleDirectives || {
        aspectRatio: '1:1',
        width: 1080,
        height: 1080,
        mood: 'professional',
        colorTone: 'neutral',
        composition: 'centered',
        textOverlay: false
      },
      negativePrompt: imgPayload.negativePrompt || 'text, watermark, blurry, low quality',
      callbackUrl
    }
  });
}

if (items.length === 0) {
  throw new Error('No valid platforms with image payloads found');
}

return items;

// Extract image URL from ImageRouter response
const postId = $('Code - Split by Platform').item.json.postId;
const platform = $('Code - Split by Platform').item.json.platform;
const prompt = $('Code - Split by Platform').item.json.prompt;
const callbackUrl = $('Code - Split by Platform').item.json.callbackUrl;

const response = $json;

// ImageRouter (OpenAI-compatible) returns data[0].url
const imageUrl = response?.data?.[0]?.url || response?.data?.[0]?.b64_json || null;

if (!imageUrl) {
  throw new Error(`ImageRouter returned no image URL for platform: ${platform}`);
}

const now = new Date().toISOString();

return [{
  json: {
    postId,
    platform,
    imageUrl,
    imagePrompt: prompt,
    callbackUrl,
    generatedAt: now
  }
}];

// Aggregate all platform image results and prepare callback
const items = $input.all();
const postId = items[0]?.json?.postId || '';
let callbackUrl = '';
try {
  callbackUrl = $('Code - Extract Image URL').all()[0]?.json?.callbackUrl || '';
} catch(e) {
  callbackUrl = $('Webhook').first().json.callbackUrl || '';
}

return [{
  json: {
    postId,
    callbackUrl,
    status: 'done',
    processedPlatforms: items.length
  }
}];
